import{_ as l,o as a,c as i,ae as r}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"《文明、现代化、价值投资与中国》深度解读系列","description":"李录著作深度解读系列：从现代化的诞生到价值投资的实践，系统梳理3.0文明理论、经济史观与价值投资理念，附AI辅助写作方法论与SEO优化实践。","frontmatter":{"title":"《文明、现代化、价值投资与中国》深度解读系列","description":"李录著作深度解读系列：从现代化的诞生到价值投资的实践，系统梳理3.0文明理论、经济史观与价值投资理念，附AI辅助写作方法论与SEO优化实践。","pubDate":"2026-05-17","heroImage":"/images/lilu-book/series-cover.jpg","keywords":["李录","文明现代化","价值投资","中国价值投资","3.0文明","现代化理论","投资理念"],"author":"黄秋钊","category":"读书笔记","tags":["李录","价值投资","现代化","经济史","投资体系"]},"headers":[],"relativePath":"posts/lilu-series-index.md","filePath":"posts/lilu-series-index.md"}'),e={name:"posts/lilu-series-index.md"};function o(n,t,h,s,d,u){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="《文明、现代化、价值投资与中国》深度解读系列" tabindex="-1">《文明、现代化、价值投资与中国》深度解读系列 <a class="header-anchor" href="#《文明、现代化、价值投资与中国》深度解读系列" aria-label="Permalink to &quot;《文明、现代化、价值投资与中国》深度解读系列&quot;">​</a></h1><h2 id="关于本书" tabindex="-1">关于本书 <a class="header-anchor" href="#关于本书" aria-label="Permalink to &quot;关于本书&quot;">​</a></h2><p>《文明、现代化、价值投资与中国》是喜马拉雅资本创始人李录的著作，由查理·芒格亲自作序。这本书汇集了李录30多年的思考精华，分为上下两篇：</p><ul><li><strong>上篇</strong>：文明、现代化与中国——从人类16000年文明史的角度，解释现代化的本质、东西方发展的差异、中国现代化的道路</li><li><strong>下篇</strong>：价值投资与理性思考——系统阐述价值投资理念，以及在中国的实践</li></ul><h2 id="核心价值" tabindex="-1">核心价值 <a class="header-anchor" href="#核心价值" aria-label="Permalink to &quot;核心价值&quot;">​</a></h2><ol><li><strong>宏大的历史视角</strong>：将人类历史分为1.0（狩猎采集）、2.0（农业文明）、3.0（现代科技文明）三个阶段</li><li><strong>现代化的精确定义</strong>：现代科技与自由市场经济结合产生的经济无限累进增长</li><li><strong>3.0文明的铁律</strong>：最大市场成为唯一市场，离开者必然落后</li><li><strong>价值投资的系统阐述</strong>：四大核心理念+道德底线+中国实践</li></ol><h2 id="阅读指南" tabindex="-1">阅读指南 <a class="header-anchor" href="#阅读指南" aria-label="Permalink to &quot;阅读指南&quot;">​</a></h2><h3 id="适合读者" tabindex="-1">适合读者 <a class="header-anchor" href="#适合读者" aria-label="Permalink to &quot;适合读者&quot;">​</a></h3><ul><li>价值投资者，希望系统理解投资本质</li><li>对中国经济前景感兴趣的投资者</li><li>想了解人类文明发展规律的读者</li><li>希望建立长期主义思维的人</li></ul><h3 id="阅读顺序建议" tabindex="-1">阅读顺序建议 <a class="header-anchor" href="#阅读顺序建议" aria-label="Permalink to &quot;阅读顺序建议&quot;">​</a></h3><p>建议按照以下顺序阅读，循序渐进理解李录的思想体系：</p><h2 id="章节导航" tabindex="-1">章节导航 <a class="header-anchor" href="#章节导航" aria-label="Permalink to &quot;章节导航&quot;">​</a></h2><h3 id="上篇-文明、现代化与中国" tabindex="-1">上篇：文明、现代化与中国 <a class="header-anchor" href="#上篇-文明、现代化与中国" aria-label="Permalink to &quot;上篇：文明、现代化与中国&quot;">​</a></h3><table tabindex="0"><thead><tr><th>章节</th><th>标题</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="/posts/lilu-ch01-modernization-born.html">第1章</a></td><td>现代化的诞生</td><td>1776年三大事件如何催生现代文明：亚当·斯密《国富论》、美国独立、瓦特蒸汽机</td></tr><tr><td><a href="/posts/lilu-ch02-essence-iron-law.html">第2章</a></td><td>现代化的本质与铁律</td><td>1+1&gt;4的知识交换效应，为什么全球化是必然，3.0文明的铁律</td></tr></tbody></table><p><strong>待更新章节：</strong></p><ul><li>老问题和新史学</li><li>文明的轨迹</li><li>人类文明的第一次飞跃</li><li>农业文明的诞生</li><li>农业文明的天花板及三次冲顶</li><li>现代化的传播与现代化的道路之争</li><li>对中国未来几十年的预测（经济/文化/社会政治）</li><li>从文明史角度看当今中美关系</li></ul><h3 id="下篇-价值投资与理性思考" tabindex="-1">下篇：价值投资与理性思考 <a class="header-anchor" href="#下篇-价值投资与理性思考" aria-label="Permalink to &quot;下篇：价值投资与理性思考&quot;">​</a></h3><table tabindex="0"><thead><tr><th>章节</th><th>标题</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="/posts/lilu-ch03-value-investing-china.html">第3章</a></td><td>价值投资在中国的展望</td><td>200年资产回报数据，价值投资四大核心理念，为什么中国能实现价值投资</td></tr></tbody></table><p><strong>待更新章节：</strong></p><ul><li>价值投资的知行合一</li><li>价值投资的常识与方法</li><li>投资是一个发现自己的过程</li><li>投资、投机与股市</li><li>从外国投资人角度看中国经济的未来</li><li>阅读、思考与感悟系列</li></ul><h2 id="核心概念速查" tabindex="-1">核心概念速查 <a class="header-anchor" href="#核心概念速查" aria-label="Permalink to &quot;核心概念速查&quot;">​</a></h2><h3 id="文明发展阶段" tabindex="-1">文明发展阶段 <a class="header-anchor" href="#文明发展阶段" aria-label="Permalink to &quot;文明发展阶段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>名称</th><th>时间</th><th>特征</th></tr></thead><tbody><tr><td>1.0</td><td>狩猎采集文明</td><td>15万年前-公元前9000年</td><td>人类与其他动物差别不大</td></tr><tr><td>2.0</td><td>农业文明</td><td>公元前9000年-1750年</td><td>农业和畜牧业，GDP增长缓慢</td></tr><tr><td>3.0</td><td>现代科技文明</td><td>1750年至今</td><td>现代科技+自由市场，经济无限累进增长</td></tr></tbody></table><h3 id="价值投资核心理念" tabindex="-1">价值投资核心理念 <a class="header-anchor" href="#价值投资核心理念" aria-label="Permalink to &quot;价值投资核心理念&quot;">​</a></h3><ol><li><strong>股票代表公司所有权</strong>——不是交易筹码，而是企业部分所有权</li><li><strong>市场是为服务你而存在</strong>——市场先生是你的仆人，不是老师</li><li><strong>安全边际</strong>——买入价格大大低于内在价值</li><li><strong>能力圈</strong>——只投资自己能理解的公司</li></ol><h3 id="关键术语" tabindex="-1">关键术语 <a class="header-anchor" href="#关键术语" aria-label="Permalink to &quot;关键术语&quot;">​</a></h3><ul><li><strong>看不见的手</strong>：自由市场中个人私利推动社会整体福利的机制</li><li><strong>1+1&gt;4</strong>：知识交换时产生的爆炸效应</li><li><strong>受托人责任</strong>：把客户的钱当作自己父母的保命钱</li><li><strong>安全边际</strong>：为预测错误预留的空间</li><li><strong>能力圈边界</strong>：知道自己不知道什么</li></ul><h2 id="实战工具" tabindex="-1">实战工具 <a class="header-anchor" href="#实战工具" aria-label="Permalink to &quot;实战工具&quot;">​</a></h2><h3 id="投资检查清单" tabindex="-1">投资检查清单 <a class="header-anchor" href="#投资检查清单" aria-label="Permalink to &quot;投资检查清单&quot;">​</a></h3><p><strong>买入前检查：</strong></p><ul><li>[ ] 我理解这家公司的商业模式吗？</li><li>[ ] 我能预测这家公司未来10年的样子吗？</li><li>[ ] 买入价格有安全边际吗？</li><li>[ ] 这笔投资在我的能力圈内吗？</li><li>[ ] 我把客户的钱当作父母的保命钱了吗？</li></ul><p><strong>持有期检查：</strong></p><ul><li>[ ] 公司的基本面发生变化了吗？</li><li>[ ] 市场价格波动影响我的判断了吗？</li><li>[ ] 我是因为恐惧还是贪婪想卖出？</li><li>[ ] 我的预测假设还成立吗？</li></ul><h3 id="推荐阅读顺序" tabindex="-1">推荐阅读顺序 <a class="header-anchor" href="#推荐阅读顺序" aria-label="Permalink to &quot;推荐阅读顺序&quot;">​</a></h3><p><strong>入门路径（1-2周）：</strong></p><ol><li>第1章《现代化的诞生》——理解3.0文明的起点</li><li>第3章《价值投资在中国的展望》——建立价值投资基础认知</li></ol><p><strong>进阶路径（1个月）：</strong> 3. 第2章《现代化的本质与铁律》——深入理解现代化机制 4. 补充阅读《穷查理宝典》——芒格的智慧</p><p><strong>深化路径（持续）：</strong> 5. 重读各章，做笔记 6. 建立自己的投资检查清单 7. 实践并记录投资案例</p><h2 id="关于本系列" tabindex="-1">关于本系列 <a class="header-anchor" href="#关于本系列" aria-label="Permalink to &quot;关于本系列&quot;">​</a></h2><p>本系列采用<strong>AI辅助写作+人工深度编辑</strong>的方式完成，遵循以下原则：</p><ol><li><strong>原文忠实</strong>：核心观点和引用均来自李录原著</li><li><strong>结构优化</strong>：按照现代博客阅读习惯重新组织</li><li><strong>SEO优化</strong>：关键词布局、元数据完善</li><li><strong>实战导向</strong>：增加投资检查清单、误区分析等实用内容</li><li><strong>深度解读</strong>：结合价值投资实践，提供延伸思考</li></ol><h3 id="写作方法论" tabindex="-1">写作方法论 <a class="header-anchor" href="#写作方法论" aria-label="Permalink to &quot;写作方法论&quot;">​</a></h3><p>本系列实践了《book-to-blog》技能的完整流程：</p><ul><li>RAG知识库构建</li><li>AI辅助写作（Prompt工程）</li><li>SEO优化（关键词、Schema标记）</li><li>质量控制（AI痕迹检测、事实核查）</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><h3 id="李录推荐书单-部分" tabindex="-1">李录推荐书单（部分） <a class="header-anchor" href="#李录推荐书单-部分" aria-label="Permalink to &quot;李录推荐书单（部分）&quot;">​</a></h3><ul><li>《穷查理宝典：查理·芒格的智慧箴言录》</li><li>《枪炮、病菌与钢铁》——贾雷德·戴蒙德</li><li>《西方将主宰多久》——伊恩·莫里斯</li><li>《文明的度量》——伊恩·莫里斯</li><li>《国富论》——亚当·斯密</li><li>《证券分析》——本杰明·格雷厄姆</li></ul><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li>《股市趋势技术分析圣经》系列——技术分析经典（待更新）</li><li><a href="/posts/black-swan.html">《黑天鹅》读书笔记</a>——理解不确定性</li></ul><hr><p><em>本系列持续更新中，建议收藏关注。如有疑问或建议，欢迎交流讨论。</em></p><p><em>最后更新：2026年5月17日</em></p>',52)])])}const b=l(e,[["render",o]]);export{c as __pageData,b as default};
